
CREATE TABLE IF NOT EXISTS games (
  id SERIAL PRIMARY KEY,
  title VARCHAR(255) NOT NULL,
  genre VARCHAR(100) NOT NULL,
  description TEXT,
  cover_url TEXT,
  screenshots TEXT[],
  rating NUMERIC(3,1) DEFAULT 0,
  votes INTEGER DEFAULT 0,
  year INTEGER,
  developer VARCHAR(255),
  publisher VARCHAR(255),
  platforms TEXT[],
  tags TEXT[],
  created_at TIMESTAMP DEFAULT NOW()
);

INSERT INTO games (title, genre, description, cover_url, rating, votes, year, developer, publisher, platforms, tags) VALUES
('Doom Eternal', 'Экшен', 'Стремительный шутер — убивай демонов с невероятной скоростью и мастерством. Ад вторгся на Землю, и только ты можешь остановить армию тьмы.', '', 9.2, 4821, 2020, 'id Software', 'Bethesda', ARRAY['PC', 'PS5', 'Xbox'], ARRAY['шутер', 'fast-paced', 'демоны']),
('Dying Light 2', 'Зомби-выживание', 'Паркур-экшен в постапокалиптическом мире. Исследуй огромный открытый мир, выживай среди орд зомби и принимай судьбоносные решения.', '', 8.4, 3102, 2022, 'Techland', 'Techland', ARRAY['PC', 'PS5', 'Xbox'], ARRAY['паркур', 'открытый мир', 'кооп']),
('The Last of Us Part II', 'Сюжеты', 'Эмоциональное путешествие мести и искупления. Один из самых глубоких и трогательных нарративов в истории игр.', '', 9.5, 8920, 2020, 'Naughty Dog', 'Sony', ARRAY['PS4', 'PS5'], ARRAY['нарратив', 'выживание', 'драма']),
('Mass Effect Legendary', 'Фантастика', 'Эпическая трилогия о командоре Шепарде и спасении галактики. Миллионы выборов, сотни часов истории.', '', 9.4, 6700, 2021, 'BioWare', 'EA', ARRAY['PC', 'PS4', 'Xbox'], ARRAY['RPG', 'галактика', 'выборы']),
('No Man''s Sky', 'Космос', 'Бесконечная вселенная для исследования — 18 квинтиллионов планет ждут тебя. Строй базы, торгуй, выживай в открытом космосе.', '', 8.7, 5430, 2016, 'Hello Games', 'Hello Games', ARRAY['PC', 'PS4', 'Xbox'], ARRAY['исследование', 'выживание', 'процедурная генерация']),
('Resident Evil Village', 'Хоррор', 'Этан Уинтерс попадает в загадочную деревню, наполненную жуткими существами. Атмосфера страха и тайны на каждом шагу.', '', 9.0, 7210, 2021, 'Capcom', 'Capcom', ARRAY['PC', 'PS5', 'Xbox'], ARRAY['выживание', 'от первого лица', 'атмосфера']),
('Red Dead Redemption 2', 'Приключения', 'Открытый мир Дикого Запада — невероятная детализация, живые NPC, эпическая история банды Ван дер Линде.', '', 9.8, 15300, 2018, 'Rockstar', 'Rockstar', ARRAY['PC', 'PS4', 'Xbox'], ARRAY['открытый мир', 'вестерн', 'RPG']),
('Civilization VI', 'Стратегические', 'Построй великую цивилизацию с нуля — от каменного века до космической эры. Тысячи часов тактической глубины.', '', 9.1, 9870, 2016, 'Firaxis', '2K', ARRAY['PC', 'iOS'], ARRAY['пошаговая', 'строительство', 'дипломатия']),
('Mortal Kombat 11', 'Файтинг', 'Жестокие и зрелищные поединки с богатым ростером персонажей. Глубокая боевая механика и захватывающий сюжетный режим.', '', 8.8, 6100, 2019, 'NetherRealm', 'WB Games', ARRAY['PC', 'PS4', 'Xbox', 'Switch'], ARRAY['PvP', 'жестокость', 'комбо']),
('Portal 2', 'Головоломка', 'Гениальные пространственные головоломки с порталами. Кооперативный режим и невероятное чувство юмора GLaDOS.', '', 9.9, 21500, 2011, 'Valve', 'Valve', ARRAY['PC', 'PS3', 'Xbox 360'], ARRAY['кооп', 'физика', 'юмор']),
('Sonic Frontiers', 'Аркада', 'Соник в открытом мире — высокоскоростные забеги по острову Стар Фолл. Новый взгляд на классическую аркадную механику.', '', 7.5, 2300, 2022, 'Sonic Team', 'Sega', ARRAY['PC', 'PS4', 'Xbox', 'Switch'], ARRAY['скорость', 'открытый мир', 'платформер']),
('Dishonored 2', 'Стелс', 'Мастерски продуманный стелс в фантастическом стимпанк-мире. Многовариантное прохождение — каждая миссия решаема десятком способов.', '', 9.0, 5420, 2016, 'Arkane', 'Bethesda', ARRAY['PC', 'PS4', 'Xbox'], ARRAY['невидимка', 'магия', 'стимпанк']),
('Forza Horizon 5', 'Гонки', 'Лучший автосимулятор в открытом мире — сотни машин, живая Мексика, невероятная графика и ощущение скорости.', '', 9.3, 8840, 2021, 'Playground Games', 'Xbox Game Studios', ARRAY['PC', 'Xbox'], ARRAY['автомобили', 'открытый мир', 'мультиплеер']),
('Need for Speed Heat', 'Гоночная игра', 'Дневные легальные гонки и ночные нелегальные заезды в неоновом городе Палм-Сити. Тюнинг, полиция и адреналин.', '', 8.1, 3700, 2019, 'Ghost Games', 'EA', ARRAY['PC', 'PS4', 'Xbox'], ARRAY['тюнинг', 'нелегальные гонки', 'неон']),
('Minecraft', 'Песочница', 'Легендарная игра-песочница без правил и ограничений. Строй, выживай, исследуй бесконечно генерируемые миры.', '', 9.6, 42000, 2011, 'Mojang', 'Microsoft', ARRAY['PC', 'PS4', 'Xbox', 'Switch', 'Mobile'], ARRAY['строительство', 'выживание', 'кооп']);
